framework_css:
:root {
  --color-bg: #000000;
  --color-bg-alt: #111111;
  --color-surface: #1a1a1a;
  --color-text: #ffffff;
  --color-text-muted: #c0c8d4;
  --color-border-subtle: #262626;
  --color-accent: #3cd01f;
  --color-accent-alt: #4caf50;

  --font-heading: "Oswald", "Helvetica", sans-serif;
  --font-body: "Source Sans 3", "Arial", sans-serif;
  --font-code: "Source Code Pro", monospace;

  --font-size-base: 14px;
  --font-size-small: 12px;
  --font-size-h1: 32px;
  --font-size-h2: 24px;
  --font-size-h3: 20px;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  --container-max-width: 980px;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  min-height: 100vh;
  background-color: var(--color-bg);
  color: var(--color-text);
  font-family: var(--font-body);
  font-size: var(--font-size-base);
  line-height: var(--line-height-normal);
  -webkit-font-smoothing: antialiased;
}

.site-wrapper {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  background-color: var(--color-bg);
}

.site-header {
  background-color: var(--color-bg);
  color: var(--color-text);
  padding: var(--space-4) var(--space-5) var(--space-5);
  position: relative;
}

.header-inner {
  max-width: var(--container-max-width);
  margin: 0 auto;
  position: relative;
}

.brand-block {
  max-width: 720px;
}

.brand-tagline {
  margin: 0 0 var(--space-1);
  color: var(--color-text-muted);
  font-size: var(--font-size-small);
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.site-title {
  margin: 0;
  font-family: var(--font-heading);
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
  text-transform: uppercase;
  letter-spacing: 0.08em;
  font-weight: 700;
}

/* Navigation toggle (hamburger) */

.nav-toggle {
  position: absolute;
  opacity: 0;
  pointer-events: none;
}

.nav-toggle-button {
  position: absolute;
  top: var(--space-4);
  right: var(--space-5);
  width: 44px;
  height: 44px;
  border-radius: 50%;
  background-color: #202020;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
}

.nav-toggle-button:focus-visible {
  outline: 2px solid var(--color-accent);
  outline-offset: 2px;
}

.nav-toggle-icon,
.nav-toggle-icon::before,
.nav-toggle-icon::after {
  display: block;
  width: 18px;
  height: 2px;
  background-color: var(--color-text);
  border-radius: 2px;
  position: relative;
}

.nav-toggle-icon::before,
.nav-toggle-icon::after {
  content: "";
  position: absolute;
  left: 0;
}

.nav-toggle-icon::before {
  top: -6px;
}

.nav-toggle-icon::after {
  top: 6px;
}

/* Overlay navigation menu */

.site-nav {
  position: fixed;
  inset: 0;
  background-color: rgba(0, 0, 0, 0.96);
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  visibility: hidden;
  transition: opacity 180ms ease-out, visibility 180ms ease-out;
  z-index: 1000;
}

.nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  text-align: center;
}

.nav-item + .nav-item {
  margin-top: var(--space-3);
}

.nav-item a {
  font-family: var(--font-heading);
  font-size: var(--font-size-h2);
  text-transform: uppercase;
  letter-spacing: 0.16em;
  text-decoration: none;
  color: var(--color-text);
  padding: var(--space-1) var(--space-3);
  display: inline-block;
}

.nav-item a:hover,
.nav-item a:focus-visible {
  color: var(--color-accent);
}

/* Show nav when toggle checked */

.nav-toggle:checked + .nav-toggle-button + .site-nav {
  opacity: 1;
  visibility: visible;
}

/* Main content */

.site-content {
  flex: 1 0 auto;
  padding: var(--space-5);
  background-color: var(--color-bg);
}

.site-content > * {
  max-width: var(--container-max-width);
  margin-left: auto;
  margin-right: auto;
}

/* Footer */

.site-footer {
  margin-top: auto;
  background-color: var(--color-bg);
  border-top: 1px solid var(--color-border-subtle);
  color: var(--color-text-muted);
  padding: var(--space-5) var(--space-5) var(--space-4);
  font-size: var(--font-size-small);
}

.footer-inner {
  max-width: var(--container-max-width);
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
}

.footer-title {
  margin: 0 0 var(--space-1);
  font-family: var(--font-heading);
  font-size: var(--font-size-h3);
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--color-text);
}

.footer-copy {
  margin: 0;
}

.footer-nav {
  margin: 0;
}

.footer-links {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
  gap: var(--space-1) var(--space-4);
}

.footer-links a {
  color: var(--color-text-muted);
  text-decoration: none;
}

.footer-links a:hover,
.footer-links a:focus-visible {
  color: var(--color-accent);
}

/* Responsiveness */

@media (min-width: 768px) {
  .site-header {
    padding-top: var(--space-5);
  }

  .nav-toggle-button {
    top: var(--space-5);
  }

  .footer-inner {
    flex-direction: row;
    align-items: flex-start;
    justify-content: space-between;
  }

  .footer-brand {
    max-width: 360px;
  }
}

@media (prefers-reduced-motion: reduce) {
  * {
    scroll-behavior: auto !important;
    animation-duration: 0.001ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.001ms !important;
  }
}
